# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import json
import boto3
from botocore.exceptions import ClientError

sns_client = boto3.client('sns')

def lambda_handler(event, context):
    try:
        message_type = event.get('message_type', 'standard')
        topic_arn = event.get('topic_arn')
        
        if not topic_arn:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'topic_arn is required'})
            }
        
        if message_type == 'standard':
            response = publish_standard_message(event)
        elif message_type == 'structured':
            response = publish_structured_message(event)
        elif message_type == 'batch':
            response = publish_batch_messages(event)
        elif message_type == 'sms':
            response = publish_sms_message(event)
        elif message_type == 'email':
            response = publish_email_message(event)
        elif message_type == 'filtered':
            response = publish_filtered_message(event)
        else:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': f'Unsupported message_type: {message_type}'})
            }
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Message(s) published successfully',
                'details': response
            })
        }
        
    except ClientError as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': 'SNS Client Error',
                'details': str(e)
            })
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': 'Internal Server Error',
                'details': str(e)
            })
        }


def publish_standard_message(event):
    topic_arn = event['topic_arn']
    message = event.get('message', '')
    subject = event.get('subject', '')
    
    params = {
        'TopicArn': topic_arn,
        'Message': message
    }
    
    if subject:
        params['Subject'] = subject
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'type': 'standard'
    }


def publish_structured_message(event):
    topic_arn = event['topic_arn']
    message_data = event.get('message', {})
    subject = event.get('subject', '')
    
    default_message = message_data.get('default', 'Default notification message')
    
    message_structure = {
        'default': default_message
    }
    
    if 'email' in message_data:
        message_structure['email'] = message_data['email']
    
    if 'sms' in message_data:
        message_structure['sms'] = message_data['sms']
    
    if 'http' in message_data:
        message_structure['http'] = json.dumps(message_data['http']) if isinstance(message_data['http'], dict) else message_data['http']
    
    if 'https' in message_data:
        message_structure['https'] = json.dumps(message_data['https']) if isinstance(message_data['https'], dict) else message_data['https']
    
    if 'sqs' in message_data:
        message_structure['sqs'] = json.dumps(message_data['sqs']) if isinstance(message_data['sqs'], dict) else message_data['sqs']
    
    if 'lambda' in message_data:
        message_structure['lambda'] = json.dumps(message_data['lambda']) if isinstance(message_data['lambda'], dict) else message_data['lambda']
    
    params = {
        'TopicArn': topic_arn,
        'Message': json.dumps(message_structure),
        'MessageStructure': 'json'
    }
    
    if subject:
        params['Subject'] = subject
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'type': 'structured',
        'protocols': list(message_structure.keys())
    }


def publish_batch_messages(event):
    topic_arn = event['topic_arn']
    messages = event.get('messages', [])
    
    if not messages:
        raise ValueError('messages array is required for batch type')
    
    results = []
    
    for idx, msg in enumerate(messages):
        message_content = msg.get('message', '')
        subject = msg.get('subject', '')
        message_attributes = msg.get('message_attributes', {})
        
        params = {
            'TopicArn': topic_arn,
            'Message': message_content
        }
        
        if subject:
            params['Subject'] = subject
        
        if message_attributes:
            params['MessageAttributes'] = format_message_attributes(message_attributes)
        
        try:
            response = sns_client.publish(**params)
            results.append({
                'index': idx,
                'message_id': response['MessageId'],
                'status': 'success'
            })
        except Exception as e:
            results.append({
                'index': idx,
                'status': 'failed',
                'error': str(e)
            })
    
    return {
        'type': 'batch',
        'total': len(messages),
        'results': results
    }


def publish_sms_message(event):
    phone_number = event.get('phone_number')
    message = event.get('message', '')
    
    if not phone_number:
        raise ValueError('phone_number is required for SMS type')
    
    params = {
        'PhoneNumber': phone_number,
        'Message': message
    }
    
    message_attributes = {}
    
    if event.get('sender_id'):
        message_attributes['AWS.SNS.SMS.SenderID'] = {
            'DataType': 'String',
            'StringValue': event['sender_id']
        }
    
    sms_type = event.get('sms_type', 'Promotional')
    message_attributes['AWS.SNS.SMS.SMSType'] = {
        'DataType': 'String',
        'StringValue': sms_type
    }
    
    if message_attributes:
        params['MessageAttributes'] = message_attributes
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'type': 'sms',
        'phone_number': phone_number
    }


def publish_email_message(event):
    topic_arn = event['topic_arn']
    subject = event.get('subject', 'Notification')
    message = event.get('message', '')
    
    params = {
        'TopicArn': topic_arn,
        'Subject': subject,
        'Message': message
    }
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'type': 'email',
        'subject': subject
    }


def publish_filtered_message(event):
    topic_arn = event['topic_arn']
    message = event.get('message', '')
    subject = event.get('subject', '')
    message_attributes = event.get('message_attributes', {})
    
    if not message_attributes:
        raise ValueError('message_attributes are required for filtered messages')
    
    params = {
        'TopicArn': topic_arn,
        'Message': message,
        'MessageAttributes': format_message_attributes(message_attributes)
    }
    
    if subject:
        params['Subject'] = subject
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'type': 'filtered',
        'attributes': list(message_attributes.keys())
    }


def format_message_attributes(attributes):
    formatted_attributes = {}
    
    for key, value in attributes.items():
        if isinstance(value, dict):
            formatted_attributes[key] = value
        elif isinstance(value, str):
            formatted_attributes[key] = {
                'DataType': 'String',
                'StringValue': value
            }
        elif isinstance(value, (int, float)):
            formatted_attributes[key] = {
                'DataType': 'Number',
                'StringValue': str(value)
            }
        elif isinstance(value, list):
            formatted_attributes[key] = {
                'DataType': 'String.Array',
                'StringValue': json.dumps(value)
            }
    
    return formatted_attributes